void MRFCircumVentRefinementOperations::MoveCircumVentSetUnderRespectiveGeomSet(const CATBaseUnknown_var &spOnRevol_1,const CATBaseUnknown_var &spOnRevol_2, CATBaseUnknown_var spOnGSMTool)
{
	HRESULT rc = E_FAIL;
	CATIMmiMechanicalFeature_var spMechFeatOfRev_1 = spOnRevol_1, spMechFeatOfRev_2 = spOnRevol_2, spMechFeatOnCircumVentSet_1, spMechFeatOnCircumVentSet_2;
	if (!!spMechFeatOfRev_1 && !!spMechFeatOfRev_2)
	{
		spMechFeatOfRev_1->GetMechanicalFather(spMechFeatOnCircumVentSet_1);
		spMechFeatOfRev_2->GetMechanicalFather(spMechFeatOnCircumVentSet_2);
	}
	if (!!spMechFeatOnCircumVentSet_1 && !!spMechFeatOnCircumVentSet_2)
	{
		CATIMmiMechanicalFeature_var spMechFeatOnCircVentFather_1, spMechFeatOnCircVentFather_2;
		spMechFeatOnCircumVentSet_1->GetMechanicalFather(spMechFeatOnCircVentFather_1);
		spMechFeatOnCircumVentSet_2->GetMechanicalFather(spMechFeatOnCircVentFather_2);

		if (!!spMechFeatOnCircVentFather_1 && !!spMechFeatOnCircVentFather_2)
		{
			CATUnicodeString nameOfFather_1 = MRFGenericUtils::GetAliasName(spMechFeatOnCircVentFather_1);
			CATUnicodeString nameOfFather_2 = MRFGenericUtils::GetAliasName(spMechFeatOnCircVentFather_2);

			int index_1 = nameOfFather_1.SearchSubString(".", 0, CATUnicodeString::CATSearchModeForward);

			int index_2 = nameOfFather_2.SearchSubString(".", 0, CATUnicodeString::CATSearchModeForward);

			nameOfFather_1 = nameOfFather_1.SubString(0, index_1);
			nameOfFather_2 = nameOfFather_2.SubString(0, index_2);

			if (index_1 == -1)
			{
				rc = spMechFeatOnCircumVentSet_1->ChangeMechanicalFather(spOnGSMTool);

				/*if (spGSMTool)
					InsertFeatureUnderGivenFeature(spMechFeatOnMiddRevol, spGSMTool);*/

			}
			else if ((nameOfFather_1.Compare("MergedSet") == 0) &&  (nameOfFather_1.Compare("LateralSet")) == 0)
			{
				rc = spMechFeatOnCircumVentSet_1->ChangeMechanicalFather(spOnGSMTool);
			}

			if (index_2 == -1)
			{
				rc = spMechFeatOnCircumVentSet_2->ChangeMechanicalFather(spOnGSMTool);
			}
			else if (!nameOfFather_2.Compare("MergedSet") && !nameOfFather_2.Compare("LateralSet"))
			{
				rc = spMechFeatOnCircumVentSet_2->ChangeMechanicalFather(spOnGSMTool);
			}

		}
	}
	CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(spOnGSMTool, 0, 0);

}

CATBoolean MRFCircumVentRefinementOperations::SetToNoShowMode(const CATIVisProperties_var & spVisu,const CATBaseUnknown_var ispSpecToCheck)
{
	CATBoolean bRetVal = CATFalse;

	if (NULL_var == spVisu)
		return bRetVal;

	CATVisPropertiesValues pPropVal;
	HRESULT hr = spVisu->GetPropertiesAtt(pPropVal, CATVPShow, CATVPGlobalType);
	if (FAILED(hr))
		return bRetVal;

	CATShowAttribut enumShowNoShow;
	pPropVal.GetShowAttr(enumShowNoShow);

	// If the part is hidden then return
	if (CATNoShowAttr == enumShowNoShow)
	{
		return bRetVal;
	}

	// Spec is not available to check
	if (CATShowAttr == enumShowNoShow && NULL_var == ispSpecToCheck)
	{
		return CATTrue;
	}
	else if (CATShowAttr == enumShowNoShow && NULL_var != ispSpecToCheck)
	{
		pPropVal.SetShow(CATNoShowAttr);
		spVisu->SetPropertiesAtt(pPropVal, CATVPShow);
		return CATTrue;
	}

	return bRetVal;
}

