CATBoolean MRFCircumVentRefinementOperations::SetColorProperties(const CATIVisProperties_var & spVisu, CATString color)
{
	CATBoolean bRetVal = CATFalse;

	if (NULL_var == spVisu)
		return bRetVal;

	CATVisPropertiesValues pPropVal;
	HRESULT hr = spVisu->GetPropertiesAtt(pPropVal, CATVPColor, CATVPLine);
	if (FAILED(hr))
		hr = spVisu->GetPropertiesAtt(pPropVal, CATVPColor, CATVPEdge);
	if (FAILED(hr))
		hr = spVisu->GetPropertiesAtt(pPropVal, CATVPColor, CATVPGlobalType); 
	if (FAILED(hr))
		return bRetVal;

	if (color == "Yellow")
		pPropVal.SetColor(255, 255, 0);
	else if (color == "Green")
		pPropVal.SetColor(0, 255, 0);
	else if (color == "Blue")
		pPropVal.SetColor(0, 0, 255);

	spVisu->SetPropertiesAtt(pPropVal, CATVPColor, CATVPLine);



	return bRetVal;
}

